// MARK: - Password Strength Validator

/// Validates password strength before storage
struct PasswordValidator {
    
    struct ValidationResult {
        let isValid: Bool
        let errors: [String]
    }
    
    static let minimumLength = 8
    static let maximumLength = 128
    
    /// Validate password meets minimum security requirements
    static func validate(_ password: String) -> ValidationResult {
        var errors: [String] = []
        
        if password.count < minimumLength {
            errors.append("Password must be at least \(minimumLength) characters long")
        }
        
        if password.count > maximumLength {
            errors.append("Password must not exceed \(maximumLength) characters")
        }
        
        let hasUppercase = password.range(of: "[A-Z]", options: .regularExpression) != nil
        if !hasUppercase {
            errors.append("Password must contain at least one uppercase letter")
        }
        
        let hasLowercase = password.range(of: "[a-z]", options: .regularExpression) != nil
        if !hasLowercase {
            errors.append("Password must contain at least one lowercase letter")
        }
        
        let hasDigit = password.range(of: "[0-9]", options: .regularExpression) != nil
        if !hasDigit {
            errors.append("Password must contain at least one digit")
        }
        
        let hasSpecial = password.range(of: "[^a-zA-Z0-9]", options: .regularExpression) != nil
        if !hasSpecial {
            errors.append("Password must contain at least one special character")
        }
        
        return ValidationResult(isValid: errors.isEmpty, errors: errors)
    }
}

// MARK: - Authentication Manager

/// High-level authentication manager combining storage and validation
final class OfflineAuthenticationManager {
    
    private let storage: SecurePasswordStorage
    private let maxFailedAttempts: Int
    private var failedAttempts: [String: (count: Int, lockoutUntil: Date?)] = [:]
    private let lockoutDuration: TimeInterval = 300 // 5 minutes
    
    init(
        serviceName: String = "com.secureapp.auth",
        maxFailedAttempts: Int = 5
    ) {
        self.storage = SecurePasswordStorage(serviceName: serviceName)
        self.maxFailedAttempts = maxFailedAttempts
    }
    
    /// Register a new account with password validation
    func register(account: String, password: String) throws -> PasswordValidator.ValidationResult {
        let validation = PasswordValidator.validate(password)
        
        guard validation.isValid else {
            return validation
        }
        
        try storage.storePassword(password, forAccount: account)
        return validation
    }
    
    /// Authenticate with rate limiting and account lockout
    func authenticate(account: String, password: String) throws -> AuthenticationResult {
        // Check for account lockout
        if let attemptInfo = failedAttempts[account],
           let lockoutUntil = attemptInfo.lockoutUntil,
           Date() < lockoutUntil {
            let remaining = lockoutUntil.timeIntervalSince(Date())
            return .lockedOut(remainingSeconds: Int(remaining))
        }
        
        do {
            let isValid = try storage.verifyPassword(password, forAccount: account)
            
            if isValid {
                // Reset failed attempts on successful auth
                failedAttempts.removeValue(forKey: account)
                return .success
            } else {
                return recordFailedAttempt(forAccount: account)
            }
        } catch PasswordStorageError.passwordNotFound {
            // Don't reveal whether account exists - same response as wrong password
            return recordFailedAttempt(forAccount: account)
        }
    }
    
    /// Change password with old password verification
    func changePassword(
        account: String,
        oldPassword: String,
        newPassword: String
    ) throws -> PasswordChangeResult {
        let validation = PasswordValidator.validate(newPassword)
        guard validation.isValid else {
            return .validationFailed(validation.errors)
        }
        
        let updated = try storage.updatePassword(
            oldPassword: oldPassword,
            newPassword: newPassword,
            forAccount: account
        )
        
        return updated ? .success : .oldPasswordIncorrect
    }
    
    /// Delete an account's stored credentials
    func deleteAccount(_ account: String) throws {
        try storage.deletePassword(forAccount: account)
        failedAttempts.removeValue(forKey: account)
    }
    
    // MARK: - Private
    
    private func recordFailedAttempt(forAccount account: String) -> AuthenticationResult {
        var info = failedAttempts[account] ?? (count: 0, lockoutUntil: nil)
        info.count += 1
        
        if info.count >= maxFailedAttempts {
            info.lockoutUntil = Date().addingTimeInterval(lockoutDuration)
            failedAttempts[account] = info
            return .lockedOut(remainingSeconds: Int(lockoutDuration))
        }
        
        failedAttempts[account] = info
        let remaining = maxFailedAttempts - info.count
        return .failed(attemptsRemaining: remaining)
    }
}

/// Result of an authentication attempt
enum AuthenticationResult {
    case success
    case failed(attemptsRemaining: Int)
    case lockedOut(remainingSeconds: Int)
}

/// Result of a password change attempt
enum PasswordChangeResult {
    case success
    case oldPasswordIncorrect
    case validationFailed([String])
}

// MARK: - Usage Example

func demonstrateUsage() {
    let authManager = OfflineAuthenticationManager()
    
    // Register
    do {
        let result = try authManager.register(account: "user@example.com", password: "MyS3cure!Pass")
        if result.isValid {
            print("Registration successful")
        } else {
            print("Password validation failed: \(result.errors)")
        }
    } catch {
        print("Registration error: \(error.localizedDescription)")
    }
    
    // Authenticate
    do {
        let result = try authManager.authenticate(account: "user@example.com", password: "MyS3cure!Pass")
        switch result {
        case .success:
            print("Authentication successful")
        case .failed(let remaining):
            print("Authentication failed. \(remaining) attempts remaining.")
        case .lockedOut(let seconds):
            print("Account locked. Try again in \(seconds) seconds.")
        }
    } catch {
        print("Authentication error: \(error.localizedDescription)")
    }
}